import React from "react";
import { Button } from "@material-ui/core";

function ProjectNav({ nav, setNav }) {
	const FILTERS = [
		"All",
		"Completed",
		"In-Progress",
		"React",
		"UI/UX",
	];

	return (
		<nav className="projectNav">
			<div>
				{FILTERS.map((btn) => {
					return (
						<Button
							key={btn}
							onClick={() => {
								setNav(btn);
							}}
							className={`${
								nav === btn ? "active" : ""
							}`}
						>
							{btn}
						</Button>
					);
				})}
			</div>
		</nav>
	);
}

export default ProjectNav;
